// Clean and regenerate package-lock.json
function cleanAndRegenerate() {
  try {
    console.log('Cleaning node_modules and regenerating package-lock.json...');
    
    // Remove node_modules and package-lock.json
    if (fs.existsSync('./node_modules')) {
      execSync('rm -rf node_modules', { stdio: 'inherit' });
    }
    
    if (fs.existsSync('./package-lock.json')) {
      fs.unlinkSync('./package-lock.json');
    }
    
    // Reinstall dependencies
    execSync('npm install', { stdio: 'inherit' });
    console.log('Clean regeneration completed successfully');
  } catch (error) {
    console.error('Clean regeneration failed:', error.message);
    process.exit(1);
  }
}

